class NestedIterator {
public:
    NestedIterator(vector<NestedInteger> &nestedList) {
        root = nestedList[0];
        stack.push_back(root);
    }

    int next() {
        if (stack.empty()) {
            return -1;
        }

        int result = stack.back();
        stack.pop_back();
        return result;
    }

    bool hasNext() {
        return !stack.empty();
    }

private:
    NestedInteger root;
    vector<NestedInteger> stack;
};
```

